// Split one email into N items, one per attachment.
// Prefers $binary (n8n native binary), falls back to $json.attachments metadata.
const items = [];
const emailJson = $input.first().json;
const emailBinary = $input.first().binary || {};

const fromRaw = emailJson.from || '';
const senderMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/(\S+@\S+)/);
const sender = senderMatch ? senderMatch[1] : fromRaw;

const binaryKeys = Object.keys(emailBinary);

if (binaryKeys.length > 0) {
  // Use binary data directly (preferred)
  for (const [key, binaryData] of Object.entries(emailBinary)) {
    items.push({
      json: {
        sender,
        subject: emailJson.subject || '',
        date: emailJson.date || new Date().toISOString(),
        originalFilename: binaryData.fileName || key,
        mimeType: binaryData.mimeType || 'application/octet-stream',
      },
      binary: { file: binaryData },
    });
  }
} else {
  // Fallback: build binary from $json.attachments[].content (Buffer)
  const attachments = emailJson.attachments || [];
  for (const att of attachments) {
    if (!att.content) continue;
    items.push({
      json: {
        sender,
        subject: emailJson.subject || '',
        date: emailJson.date || new Date().toISOString(),
        originalFilename: att.filename || att.name || 'attachment',
        mimeType: att.contentType || 'application/octet-stream',
      },
      binary: {
        file: {
          data: Buffer.isBuffer(att.content) ? att.content.toString('base64') : att.content,
          mimeType: att.contentType || 'application/octet-stream',
          fileName: att.filename || att.name || 'attachment',
          fileExtension: (att.filename || '').split('.').pop() || '',
        },
      },
    });
  }
}

return items;

// Build YAML frontmatter + note body.
// Note name: YYYY-MM-DD + markitdown title (fallback: filename → subject)
const conv = $input.first().json;  // { markdown, title, filename, source_type }
const email = $('Split Attachments').first().json;

// Date from email (ISO string)
const d = new Date(email.date);
const dateStr = isNaN(d.getTime())
  ? new Date().toISOString().split('T')[0]
  : d.toISOString().split('T')[0];

// Title fallback chain: markitdown title → filename stem → email subject → 'untitled'
const rawTitle = (conv.title || '').trim()
  || (email.originalFilename || '').replace(/\.[^.]+$/, '').trim()
  || (email.subject || '').trim()
  || 'untitled';
const safeTitle = rawTitle.replace(/[\/\\:*?"<>|]/g, '-').substring(0, 100).trim();
const noteName = `${dateStr} ${safeTitle}`;
const path = `002 - incoming/${noteName}.md`;

// YAML frontmatter
const subjectSafe = (email.subject || '').replace(/"/g, "'");
const fm = [
  '---',
  `sender: "${email.sender || email.from || ''}"`,
  `subject: "${subjectSafe}"`,
  `received: ${dateStr}`,
  `source_type: ${conv.source_type || 'document'}`,
  '---',
].join('\n');

const content = `${fm}\n\n${conv.markdown || ''}`;

return [{ json: {
  body: JSON.stringify({ path, content, overwrite: true }),
  path,
  markdown: conv.markdown || '',
  noteName,
} }];

// Extract email metadata and raw body text. Handles plain-text and HTML emails.
const emailJson = $input.first().json;

const d = new Date(emailJson.date || new Date());
const dateStr = d.toISOString().split('T')[0];
const pad = n => n.toString().padStart(2, '0');
const timeStr = `${pad(d.getHours())}-${pad(d.getMinutes())}`;
const sentFormatted = `${pad(d.getDate())}.${pad(d.getMonth()+1)}.${d.getFullYear()} ${pad(d.getHours())}.${pad(d.getMinutes())}.${pad(d.getSeconds())}`;

const subject = (emailJson.subject || 'no-subject').trim();
const safeSubject = subject.replace(/[\/\\:*?"<>|]/g, '-').substring(0, 100).trim();
const noteName = `${dateStr} ${timeStr} ${safeSubject}`;
const path = `553 - emails/${noteName}.md`;

// Display name → Lastname Firstname wikilink
const fromRaw = emailJson.from || '';
const displayMatch = fromRaw.match(/^([^<]+)</) || fromRaw.match(/^([^@]+)/);
const displayName = (displayMatch ? displayMatch[1] : fromRaw).trim();
const nameParts = displayName.split(/\s+/).filter(Boolean);
const wikiName = nameParts.length >= 2
  ? `${nameParts[nameParts.length - 1]} ${nameParts.slice(0, -1).join(' ')}`
  : displayName;

// Body: prefer plain text; strip HTML tags as fallback
function stripHtml(html) {
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}
const rawBody = emailJson.text
  ? emailJson.text.trim()
  : emailJson.html ? stripHtml(emailJson.html) : '';

return [{ json: { subject, wikiName, sentFormatted, dateStr, timeStr, noteName, path, rawBody } }];

const email = $input.first().json;
const system = 'You are a concise executive assistant. Extract the key points from this email as 3-5 bullet points. Be specific: include names, numbers, dates, decisions, and action items where present. Output ONLY the bullet points starting with "- ". No preamble, no headings.';
const prompt = `Subject: ${email.subject}\nFrom: ${email.wikiName}\nDate: ${email.sentFormatted}\n\n${email.rawBody}`;
return [{ json: { body: JSON.stringify({ model: 'qwen3.5:27b', stream: false, think: false, num_ctx: 32768, system, prompt }) } }];

// Assemble final note: frontmatter + summary + full email body
const email = $('Build Email Body').first().json;
const summary = ($input.first().json.response || '').trim();

const fm = ['---', `subject: ${email.subject}`, `from: ${email.wikiName}`, `sent: ${email.sentFormatted}`, '---'].join('\n');
const content = [
  fm,
  '',
  `Send by [[${email.wikiName}]]`,
  '',
  `# ${email.subject}`,
  '',
  '## Key Points',
  summary,
  '',
  '---',
  '',
  '## Full Email',
  email.rawBody,
].join('\n');

return [{ json: {
  body: JSON.stringify({ path: email.path, content, overwrite: true }),
  path: email.path,
  markdown: content,
  noteName: email.noteName,
} }];

// Retrieve note data from whichever path ran (attachment or email body).
let note = null;
try { note = $('Assemble Email Note').first().json; } catch(e) {}
if (!note || !note.path) { try { note = $('Build Note Body').first().json; } catch(e) {} }
const path = (note && note.path) || '';
const text = (note && note.markdown) || '';
return [{ json: { body: JSON.stringify({
  id: path,
  text: text,
  collection: 'vault',
  metadata: { source: path, type: 'document' },
}) } }];

// Retrieve note data from whichever path ran (attachment or email body).
let note = null;
try { note = $('Assemble Email Note').first().json; } catch(e) {}
if (!note || !note.path) { try { note = $('Build Note Body').first().json; } catch(e) {} }
const noteName = (note && note.noteName) || 'unknown';
const path = (note && note.path) || '';
const text = `Email saved:\n<b>${noteName}</b>\n\n<code>${path}</code>`;
return [{ json: { body: JSON.stringify({
  chat_id: $env.PIPELINE_CHAT_ID,
  text,
  parse_mode: 'HTML',
}) } }];
